  })
});
form.patchValue({ address: { city: 'London' } });

What is the value of form.value.address.zip after patchValue?

Given this template-driven code:

this.fb.group({
  items: this.fb.array([
    this.fb.control('first'),
    this.fb.control('second')
  ])
