How do you access the FormArray instance programmatically?

What does the following custom validator return when the control value is valid?

export function noSpaces(control: AbstractControl): ValidationErrors | null {
  return control.value?.includes(' ') ? { hasSpaces: true } : null;
}

Given this code:

this.http.get<User[]>('/api/users').pipe(
  catchError(err => {
    console.error(err);
    return of([]);
  })
);

What does this stream emit when the HTTP request fails?

Given this directive:

@Directive({ selector: '[appHighlight]' })
export class HighlightDirective {
  @HostBinding('style.backgroundColor') bgColor = 'yellow';
  @HostListener('mouseenter') onEnter() { this.bgColor = 'orange'; }
  @HostListener('mouseleave') onLeave() { this.bgColor = 'yellow'; }
}

What does this directive do?

